INSERT INTO `projects` (`id`, `name`, `builderName`, `description`, `location`, `city`, `latitude`, `longitude`, `status`, `priceRange`, `minPrice`, `maxPrice`, `configurations`, `reraNumber`, `possessionDate`, `totalUnits`, `towers`, `floors`, `coverImage`, `videoUrl`, `brochureUrl`, `featured`, `createdAt`, `updatedAt`, `masterPlanUrl`, `builderDescription`, `builderLogo`, `builderEstablished`, `builderProjects`, `slug`, `badge`, `customBadgeText`) VALUES (1, 'Pride Purple ', 'Pride Group', 'Pride Purple Park Eden offers premium 2 & 3 BHK apartments in the heart of Kharadi. With world-class amenities and excellent connectivity to IT hubs, this project is perfect for modern families.', 'Kharadi', 'Pune', '18.56790000', '73.91430000', 'Under Construction', '₹1.80 - ₹2.25Cr', '1800000.00', '2249999.00', '3, 4 BHK', 'P52100017620', '2028-12-01 05:00:00', 450, 3, 18, '/images/property-kharadi-1.jpg', 'https://www.youtube.com/watch?v=CUYFXeA-Rj4', 'https://www.pridepurpleproperties.com/brochure/park-eden-brochure.pdf', 1, '2026-01-25 07:12:09', '2026-02-04 06:59:45', NULL, 'Pride Purple Group is one of Pune\'s most trusted real estate developers, established in 1995. With over 25 years of excellence, they have delivered 50+ residential and commercial projects across Pune. Known for innovative designs, quality construction, and timely delivery, Pride Purple has earned the trust of over 15,000 happy homeowners. Their projects are characterized by premium amenities, strategic locations, and sustainable building practices.', '/images/builders/pride-group.jpg', 1995, 50, 'pride-purple-park-eden', 'Best Seller', 'Pre-Launch');
INSERT INTO `projects` (`id`, `name`, `builderName`, `description`, `location`, `city`, `latitude`, `longitude`, `status`, `priceRange`, `minPrice`, `maxPrice`, `configurations`, `reraNumber`, `possessionDate`, `totalUnits`, `towers`, `floors`, `coverImage`, `videoUrl`, `brochureUrl`, `featured`, `createdAt`, `updatedAt`, `masterPlanUrl`, `builderDescription`, `builderLogo`, `builderEstablished`, `builderProjects`, `slug`, `badge`, `customBadgeText`) VALUES (30001, ' Caladium', 'Casagrand', 'Casagrand Caladium, a new launch by the renowned Casagrand Group, is set in the thriving location of Upper Kharadi, Pune. Spread across a well-planned 2.8-acre land parcel, this premium residential community offers thoughtfully designed 2 & 3 BHK apartments starting at just ₹99 Lakhs*. With 20+ world-class amenities, contemporary architecture, and lush landscaped spaces, the project promises a perfect blend of luxury, comfort, and connectivity. Its strategic location ensures easy access to IT hubs, top schools, shopping centres, and entertainment zones, making it an ideal choice for modern families', '14/2, Solacia Internal Road, RMC Garden, Wagholi, Wagholi, Pune, Maharashtra 412207, India', 'Pune', '18.57212330', '73.97445120', 'Under Construction', '1.2 Cr - 1.70 Cr', '12000000.00', '1700000.00', '2,3 BHK', 'P52100080302', '2029-03-30 04:00:00', 334, 5, 6, '/images/property-kharadi-1.jpg', 'https://www.youtube.com/watch?v=aR74le2OvPU', 'https://drive.google.com/file/d/1oxwEdYkhb4s-22U-6j3dv7Q19YSBhcCI/view?usp=drivesdk', 0, '2026-01-30 13:08:49', '2026-02-04 06:59:45', 'https://d2xsxph8kpxj0f.cloudfront.net/310419663026719415/aSHZEBwUmWTuA7HAwuTg3z/property-images/1769859557552-1UNIyATbzG.jpeg', 'Established in 2003 by Mr. Arun M N, Casagrand Premier Builder Limited (CPBL) is a premier South Indian real estate developer headquartered in Chennai. Over 20+ years, it has developed over 26 msf across 107+ projects in Chennai, Bengaluru, and Coimbatore, focusing on residential apartments, villas, and expanding into commercial/warehousing sectors', 'https://d2xsxph8kpxj0f.cloudfront.net/310419663026719415/aSHZEBwUmWTuA7HAwuTg3z/property-images/1769760820455-PLDjD1xIVG.png', 2003, 107, 'caladium', 'Best Seller', 'Pre-Launch');
INSERT INTO `projects` (`id`, `name`, `builderName`, `description`, `location`, `city`, `latitude`, `longitude`, `status`, `priceRange`, `minPrice`, `maxPrice`, `configurations`, `reraNumber`, `possessionDate`, `totalUnits`, `towers`, `floors`, `coverImage`, `videoUrl`, `brochureUrl`, `featured`, `createdAt`, `updatedAt`, `masterPlanUrl`, `builderDescription`, `builderLogo`, `builderEstablished`, `builderProjects`, `slug`, `badge`, `customBadgeText`) VALUES (60001, 'kohinoor keleido phase 2', 'kohinoor', 'Discover the charm of peaceful and refined living with Kohinoor New Launch and Kohinoor Kaleido in Pune, thoughtfully developed by Kohinoor Group. This residential project offers beautifully designed two and three bedroom homes that bring comfort, joy, and functionality to everyday life through smart layouts, modern amenities, and generous open spaces. Safety and security are given top priority at Kohinoor Kaleido Pune, with advanced surveillance systems ensuring a secure living environment. The grand entrance gate and elegantly designed lobby create a warm and welcoming first impression for residents and guests alike.', 'Upper Kharadi Main Rd, Wagholi, Pune, Maharashtra 412207, India', 'Pune', '18.56775270', '73.96278230', 'Under Construction', '98 lac - 1.37 Cr', NULL, '13700000.00', '2,3 BHK', 'P52100046027', '2019-01-01 05:00:00', NULL, 6, 8, '/images/property-kharadi-1.jpg', 'https://youtu.be/X_8Dh9rXWlI?si=nX4_Z0RwxZZ5CmbD', NULL, 0, '2026-02-01 18:48:10', '2026-02-04 06:59:45', 'https://d2xsxph8kpxj0f.cloudfront.net/310419663026719415/aSHZEBwUmWTuA7HAwuTg3z/property-images/1769954877214-1jZlfbsngM.jpeg', NULL, NULL, NULL, 49, 'kohinoor-keleido-phase-2', 'New', 'new launch');
INSERT INTO `projects` (`id`, `name`, `builderName`, `description`, `location`, `city`, `latitude`, `longitude`, `status`, `priceRange`, `minPrice`, `maxPrice`, `configurations`, `reraNumber`, `possessionDate`, `totalUnits`, `towers`, `floors`, `coverImage`, `videoUrl`, `brochureUrl`, `featured`, `createdAt`, `updatedAt`, `masterPlanUrl`, `builderDescription`, `builderLogo`, `builderEstablished`, `builderProjects`, `slug`, `badge`, `customBadgeText`) VALUES (60002, 'Godrej River Crest', '   Godrej', 'Godrej Properties, established in 1990 as part of the Godrej Group, is a premier Indian real estate developer headquartered in Mumbai. Renowned for sustainability, innovation, and trust, it develops residential, commercial, and township projects across 10+ major Indian cities. Listed on BSE/NSE, it is a top-tier, high-growth develope', 'Upper Kharadi Main Rd, Wagholi, Pune, Maharashtra 412207, India', 'Pune', '18.56775270', '73.96278230', 'Under Construction', '₹2.05- ₹2.60Cr', '20500000.00', '26000000.00', '3,4 BHK', 'P52100077127', '2029-10-01 04:00:00', 350, 2, 26, '/images/property-kharadi-1.jpg', NULL, NULL, 0, '2026-02-01 19:46:01', '2026-02-04 06:59:45', 'https://d2xsxph8kpxj0f.cloudfront.net/310419663026719415/aSHZEBwUmWTuA7HAwuTg3z/property-images/1770115576291-u7EEYXH3xm.jpeg', NULL, NULL, NULL, NULL, 'godrej-river-crest', 'Premium', 'new launch');
